vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;

vec4 ra = vec4 (1,-1,1,1);
//uv1 = multiply(uv1,ra);

vec2 tmp = uv1;

tmp.x = .1*sin(uv1.x*127) + .0;
tmp.y = .1*sin(uv1.y*127) + .0;
uv1 = tmp;



vec3 ret1 = clamp((GetBlur1(vUv))-1,-.1,.1);

vec2 h1 = 1*uv1.xy + 0*uv1.yx;
vec3 crisp = texture(sampler_main, vUv-lum(ret1.yx)*.4*(sin(h1)) ) ;

vec3 blur = GetBlur1 (vUv+vec2(1*ret1.x,ret1.y)*0) ;

ret = clamp01( crisp);

 ret *= 0.99 ;
  ret -= 0.005;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  uv0 = vUv;
screen3 = vec3 ((vUv-.5)*uAspect.xy,1);

//-----------Profiled landscape
ret1 = 0;
dist = .5;
for (int m=1; m <= quality; m++) {
  rsl = project (dist)+vec3 (mov,0);
  lprof =  lum(GetBlur1(fract(rsl.xy)).g)-.5 ; //mittelwert null !#
  dist += -lprof/quality*depth/rsl.z;
}
rsl.xy = fract(rsl.xy);
neu = GetPixel(fract(rsl.xy))/2*vec3(1,1,0);

//----------Determine water surface
float water = clamp01(8-64*neu.g+.4*sin(14*rsl.xy+uTime));
rsl.xy += water* .01*texture(sampler_noise_hq,16*rsl.xy+uTime*.2).rg;;
neu += water*vec3 (0,0,.1);

//----------sun and reflection
vec2 k1 = vec2(32,8);
dz.x = lum(GetPixel (rsl.xy-hor).gb*k1) - lum(GetPixel (rsl.xy+hor).gb*k1);
dz.y = lum(GetPixel (rsl.xy-ver).gb*k1) - lum(GetPixel (rsl.xy+ver).gb*k1);
sun = clamp01(.1/length(sin(rsl.xy*6+uTime*.2)+dz*4));

neu += 8*sun*(0.2+neu)*water;
neu += -dot(dz,vec2(q1,q2));

//--------- sprinkle grain
neu *= 1-.4*texture(sampler_noise_lq,rsl.xy*2).r;


ret = neu ;


  fragColor = ret;
}
